def p(g):
    h, w = len(g), len(g[0])
    v = [[False] * w for _ in range(h)]
    o = [r[:] for r in g]
    for i in range(h):
        for j in range(w):
            if g[i][j] == 5 and not v[i][j]:
                # BFS to find the whole connected component of 5s
                q = [(i, j)]
                v[i][j] = True
                comp = []
                while q:
                    r, c = q.pop()
                    comp.append((r, c))
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < h and 0 <= nc < w and not v[nr][nc] and g[nr][nc] == 5:
                            v[nr][nc] = True
                            q.append((nr, nc))
                # bounding box
                min_r = min(r for r, _ in comp)
                max_r = max(r for r, _ in comp)
                min_c = min(c for _, c in comp)
                max_c = max(c for _, c in comp)
                Lr = max_r - min_r + 1
                Lc = max_c - min_c + 1
                if Lr != Lc or Lr < 3:
                    continue
                L = Lr
                # check perfect hollow square
                ok = True
                # border must be all 5
                for r in range(min_r, max_r + 1):
                    if g[r][min_c] != 5 or g[r][max_c] != 5:
                        ok = False
                for c in range(min_c, max_c + 1):
                    if g[min_r][c] != 5 or g[max_r][c] != 5:
                        ok = False
                # interior must be all 0
                for r in range(min_r + 1, max_r):
                    for c in range(min_c + 1, max_c):
                        if g[r][c] != 0:
                            ok = False
                # size check: perimeter cells exactly 4*L-4
                if len(comp) != 4 * L - 4:
                    ok = False
                if ok:
                    fill = L + 3
                    for r in range(min_r + 1, max_r):
                        for c in range(min_c + 1, max_c):
                            o[r][c] = fill
    return o

